#!/usr/bin/env python3
"""
CLI计算器 - 支持基本运算和科学计算
使用方法：
    交互模式: python calculator.py
    命令行模式: python calculator.py "2 + 3 * 4"
"""

import sys
import math
import re
from typing import Union


class Calculator:
    """计算器类，支持基本运算和科学计算"""

    def __init__(self):
        self.history = []

    def add(self, a: float, b: float) -> float:
        """加法"""
        return a + b

    def subtract(self, a: float, b: float) -> float:
        """减法"""
        return a - b

    def multiply(self, a: float, b: float) -> float:
        """乘法"""
        return a * b

    def divide(self, a: float, b: float) -> float:
        """除法"""
        if b == 0:
            raise ValueError("错误：除数不能为零")
        return a / b

    def power(self, a: float, b: float) -> float:
        """幂运算"""
        return a ** b

    def modulo(self, a: float, b: float) -> float:
        """取模"""
        if b == 0:
            raise ValueError("错误：除数不能为零")
        return a % b

    def sqrt(self, a: float) -> float:
        """平方根"""
        if a < 0:
            raise ValueError("错误：不能对负数开平方")
        return math.sqrt(a)

    def sin(self, a: float) -> float:
        """正弦（弧度）"""
        return math.sin(a)

    def cos(self, a: float) -> float:
        """余弦（弧度）"""
        return math.cos(a)

    def tan(self, a: float) -> float:
        """正切（弧度）"""
        return math.tan(a)

    def log(self, a: float, base: float = math.e) -> float:
        """对数"""
        if a <= 0:
            raise ValueError("错误：对数参数必须大于零")
        if base <= 0 or base == 1:
            raise ValueError("错误：对数底数必须大于零且不等于1")
        return math.log(a, base)

    def ln(self, a: float) -> float:
        """自然对数"""
        if a <= 0:
            raise ValueError("错误：对数参数必须大于零")
        return math.log(a)

    def exp(self, a: float) -> float:
        """e的幂"""
        return math.exp(a)

    def abs(self, a: float) -> float:
        """绝对值"""
        return abs(a)

    def factorial(self, n: int) -> int:
        """阶乘"""
        if n < 0:
            raise ValueError("错误：阶乘参数不能为负数")
        if n > 170:
            raise ValueError("错误：阶乘参数太大")
        return math.factorial(n)

    def evaluate_expression(self, expression: str) -> Union[float, int]:
        """评估数学表达式"""
        # 移除空格
        expr = expression.replace(' ', '')

        # 替换数学函数
        expr = self._replace_functions(expr)

        try:
            # 使用eval安全计算表达式
            # 允许的字符和函数
            allowed_chars = set('0123456789+-*/.()^%')
            if not all(c in allowed_chars for c in expr):
                raise ValueError("错误：包含非法字符")

            # 替换^为**
            expr = expr.replace('^', '**')

            result = eval(expr)
            return result
        except Exception as e:
            raise ValueError(f"计算错误: {str(e)}")

    def _replace_functions(self, expr: str) -> str:
        """替换数学函数为Python函数"""
        # 替换常量
        expr = expr.replace('pi', str(math.pi))
        expr = expr.replace('e', str(math.e))

        return expr

    def calculate(self, expression: str) -> Union[float, int]:
        """计算表达式并保存到历史记录"""
        result = self.evaluate_expression(expression)
        self.history.append((expression, result))
        return result

    def show_history(self, n: int = 10):
        """显示历史记录"""
        if not self.history:
            print("暂无历史记录")
            return

        print(f"\n最近{min(n, len(self.history))}条计算记录:")
        print("-" * 50)
        for i, (expr, result) in enumerate(self.history[-n:], 1):
            print(f"{i}. {expr} = {result}")
        print("-" * 50)

    def clear_history(self):
        """清空历史记录"""
        self.history = []
        print("历史记录已清空")


def print_help():
    """打印帮助信息"""
    help_text = """
