"""
    print(help_text)


def interactive_mode():
    """交互式模式"""
    calc = Calculator()
    print("\n🧮 CLI 计算器已启动!")
    print("输入 'help' 查看帮助，'quit' 退出\n")

    while True:
        try:
            user_input = input(">>> ").strip()

            if not user_input:
                continue

            # 处理命令
            if user_input.lower() == 'quit':
                print("谢谢使用，再见！👋")
                break
            elif user_input.lower() == 'help':
                print_help()
                continue
            elif user_input.lower() == 'history':
                calc.show_history()
                continue
            elif user_input.lower() == 'clear':
                calc.clear_history()
                continue

            # 计算表达式
            result = calc.calculate(user_input)

            # 格式化输出
            if isinstance(result, float) and result.is_integer():
                print(f"= {int(result)}")
            else:
                print(f"= {result}")

        except ValueError as e:
            print(f"❌ {e}")
        except KeyboardInterrupt:
            print("\n\n谢谢使用，再见！👋")
            break
        except Exception as e:
            print(f"❌ 发生错误: {e}")


def command_line_mode(expression: str):
    """命令行模式"""
    calc = Calculator()
    try:
        result = calc.calculate(expression)
        if isinstance(result, float) and result.is_integer():
            print(int(result))
        else:
            print(result)
    except Exception as e:
        print(f"错误: {e}", file=sys.stderr)
        sys.exit(1)


def main():
    """主函数"""
    if len(sys.argv) > 1:
        # 命令行模式
        expression = ' '.join(sys.argv[1:])
        command_line_mode(expression)
    else:
        # 交互式模式
        interactive_mode()


if __name__ == "__main__":
    main()
